using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI setup ---
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddSingleton<ResearchNotes>();
services.AddHttpClient("search");

services.AddChatClient(b => b
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var provider = services.BuildServiceProvider();

// --- Tools ---
var notes = provider.GetRequiredService<ResearchNotes>();
var httpFactory = provider.GetRequiredService<IHttpClientFactory>();

var searchTool = AIFunctionFactory.Create(
    async ([Description("The search query")] string query) =>
    {
        using var http = httpFactory.CreateClient("search");
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var doc = await http.GetFromJsonAsync<JsonElement>(url);
            var results = new List<string>();

            // Abstract (instant answer)
            if (doc.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } text)
                results.Add($"[Summary] {text}");

            // Related topics
            if (doc.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var t) && t.GetString() is { Length: > 0 } topicText)
                        results.Add($"[Related] {topicText}");
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try a different or simpler query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    },
    "web_search",
    "Search the web for information on a topic. Returns summaries and related content.");

var addNoteTool = AIFunctionFactory.Create(
    ([Description("Title or label for the note")] string title,
     [Description("Content of the note")] string content) =>
    {
        notes.Add(title, content);
        return $"Note saved: \"{title}\" ({content.Length} chars)";
    },
    "add_note",
    "Save a research note with a title and content. Use this to record important findings.");

var viewNotesTool = AIFunctionFactory.Create(
    () => notes.Count == 0
        ? "No notes yet."
        : notes.Format(),
    "view_notes",
    "View all saved research notes.");

// --- Agent ---
var chatClient = provider.GetRequiredService<IChatClient>();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [searchTool, addNoteTool, viewNotesTool],
        },
    });

// --- Run ---
Console.WriteLine("╔═══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)         ║");
Console.WriteLine("╠═══════════════════════════════════════╣");
Console.WriteLine("║ Enter a topic to research, or 'quit'. ║");
Console.WriteLine("╚═══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a thorough research assistant. When given a topic:
            1. Search the web multiple times with different queries to gather diverse information.
            2. Save key findings as notes using the add_note tool.
            3. After gathering enough information, review your notes with view_notes.
            4. Provide a well-organized summary of your findings to the user.
            Be concise but comprehensive. Cite the information you found.
            """),
        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
    };

    Console.WriteLine($"\n🔍 Researching: {topic}\n");

    try
    {
        var response = await agent.RunAsync(
            messages,
            session: null,
            new ChatClientAgentRunOptions(new ChatOptions { MaxOutputTokens = 4096 }),
            CancellationToken.None);

        Console.WriteLine("═══ Research Summary ═══");
        Console.WriteLine(response.Text);
        Console.WriteLine("════════════════════════\n");

        if (notes.Count > 0)
        {
            Console.WriteLine($"📝 {notes.Count} note(s) saved during research.\n");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"❌ Error: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

// --- Research notes store ---
sealed class ResearchNotes
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content) => _notes.Add((title, content));

    public void Clear() => _notes.Clear();

    public string Format()
    {
        var sb = new System.Text.StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i].Title}");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

